+        match this.stream.poll_next(cx) {
+            Poll::Ready(Some(item)) => match (this.f)(state, item) {
+                Some(value) => Poll::Ready(Some(value)),
+                None => {
+                    *this.state = None;
+                    Poll::Ready(None)
+                }
+            },
+            Poll::Ready(None) => Poll::Ready(None),
+            Poll::Pending => Poll::Pending,
+        }
+    }
